import { logger } from "hono/logger";
import { Router, json, cors, Swagger } from "@ecosy/hoapp";
import v1 from "./router/v1";

// 1. Setup Swagger DIP
const swagger = new Swagger({
  base: "/docs",
  info: { title: "CFCMS Backend API", version: "2.0.0" }
});

const app = Router.create("/");

app.use("*", cors({
  origins: [
    "http://localhost:5173",
    "http://localhost:3000",
    ".pages.dev"
  ]
}));

app.use("*", logger());
app.use("/v1/*", json);

Router.add(app, v1, swagger.getRouter());

export default app;
