import { cors as honoCors } from "hono/cors";

export const DEFAULT_ALLOWED_METHODS = ["GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS"];
export const DEFAULT_ALLOWED_HEADERS = ["Content-Type", "Authorization"];

export interface CorsOptions {
  origins?: string[];
  methods?: string[];
  credentials?: boolean;
  headers?: string[];
  maxAge?: number;
}

export const cors = (options: CorsOptions = {}) => {
  const {
    origins = [],
    credentials = true,
    maxAge = 86400,
    methods = DEFAULT_ALLOWED_METHODS,
    headers = DEFAULT_ALLOWED_HEADERS,
  } = options;

  return honoCors({
    origin: (origin) => {
      if (!origin) {
        return null; // Request không có header Origin (cùng site) thường được cho qua, nhưng ở đây tuỳ Hono xử lý
      }

      // Nếu có "*" thì cho phép tất cả các domain
      if (origins.includes("*")) {
        return origin;
      }

      // Khớp chính xác hoàn toàn (exact match)
      if (origins.includes(origin)) {
        return origin;
      }

      // Kiểm tra dạng subdomain (bắt đầu bằng dấu ".")
      for (const allowed of origins) {
        if (allowed.startsWith(".")) {
          try {
            const url = new URL(origin);
            if (url.hostname.endsWith(allowed)) {
              return origin;
            }
          } catch {}
        }
      }

      return null;
    },
    allowMethods: [...methods],
    allowHeaders: [...headers],
    credentials,
    maxAge,
  });
};

cors.DEFAULT_METHODS = DEFAULT_ALLOWED_METHODS;
cors.DEFAULT_HEADERS = DEFAULT_ALLOWED_HEADERS;
